def queue_row_sync(doctype: str, names: list, notify_user: str = "Administrator"):
    frappe.enqueue("nce_sync.utils.data_sync.run_sync_doctype_rows_job", queue="default", timeout=3600, doctype=doctype, names=list(names), user=notify_user)

